def verify_totp(
    secret_b32: str,
    code: str,
    for_time: Optional[int] = None,
    step: int = 30,
    t0: int = 0,
    digits: int = 6,
    digestmod=hashlib.sha1,
    valid_window: int = 1,
) -> bool:
    if for_time is None:
        for_time = int(time.time())
