def build_otpauth_uri(
    secret_b32: str,
    account_name: str,
    issuer: str,
    digits: int = 6,
    period: int = 30,
    algorithm: str = "SHA1",
) -> str:
    label = f"{issuer}:{account_name}"
    label_enc = urllib.parse.quote(label)
    params = {
        "secret": secret_b32,
        "issuer": issuer,
        "algorithm": algorithm.upper(),
        "digits": str(digits),
        "period": str(period),
    }
    query = urllib.parse.urlencode(params, quote_via=urllib.parse.quote)
    return f"otpauth://totp/{label_enc}?{query}"


def generate_qr_code(otpauth_uri: str, file_path: str) -> None:
    qr = qrcode.QRCode(
        version=None,
        error_correction=qrcode.constants.ERROR_CORRECT_M,
        box_size=10,
        border=4,
    )
    qr.add_data(otpauth_uri)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")
    img.save(file_path)


